// // This module implements a 8-bit register with an enable signal and an asynchronous clear.
// The register stores the input data when the enable signal is low, and clears the register when the clear signal is low.
module reg_8bit (
    input clk,
    input en,
    input clr,
    input [7:0] d,
    output reg [7:0] q
);

always @(posedge clk or posedge clr)
    if (clr)
        q <= 8'b00000000;
    else if (en)
        q <= d;

endmodule
